//! Portable Rhai build-script execution over project storage.
//!
//! Scripts only see typed project-relative storage through the `project`, `output`, and `build`
//! scope objects. Evaluation is synchronous against one immutable [`ProjectView`]; generated bytes
//! and build directives stay buffered until a successful evaluation is committed in one
//! revision-checked transaction.

use alloc::borrow::ToOwned;
use alloc::collections::{BTreeMap, BTreeSet};
use alloc::format;
use alloc::rc::Rc;
use alloc::string::{String, ToString};
use alloc::vec::Vec;
use core::cell::RefCell;
use core::error::Error as CoreError;
use core::fmt;

use jals_config::Manifest;
use jals_storage::{
    ArtifactCache, CacheBackend, CacheKey, CacheNamespace, ContentDigest, FileKey, ProjectView,
    Revision,
};
use serde::{Deserialize, Serialize};

use crate::task::{TaskPlan, TaskPlanLimits};

// Both bumped for build features: the Rhai surface gained `build.feature`/`build.features` (API),
// and `FingerprintInputsWire` gained a required `features` field (state). The API bump is the
// load-bearing one — it reseeds the cache key (`cache_key_seed`), so a pre-feature state is never
// fetched and decoded in the first place.
const BUILD_SCRIPT_API_VERSION: u32 = 5;
const BUILD_SCRIPT_STATE_VERSION: u32 = 5;
const BUILD_ARTIFACT_ROOT: &str = "target/jals/build";
/// Everything `jals` owns under the project: build artifacts, the verified cache, acquired
/// dependencies. All of it is derived, so none of it is an input to a script's fingerprint.
const MANAGED_ROOT: &str = "target/jals";
const MANIFEST_FILE: &str = "jals.toml";

/// Project directory reserved for all Rhai build-script artifacts.
pub const RHAI_BUILD_ROOT: &str = "target/jals/build/rhai";

/// Directory under [`RHAI_BUILD_ROOT`] where script-generated files are published.
pub const RHAI_OUTPUT_ROOT: &str = "target/jals/build/rhai/out";

/// Cache identity for one build-script project.
///
/// Dependency projects must use a scope derived from their stable content identity. The root
/// project uses [`ROOT`](Self::ROOT). Scope values are opaque so callers cannot accidentally depend
/// on their cache encoding.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct BuildScriptCacheScope(Option<ContentDigest>);

impl BuildScriptCacheScope {
    /// Distinguished cache scope for the root project executed by [`execute_build_script`].
    pub const ROOT: Self = Self(None);

    /// Construct an isolated dependency-project cache scope from a stable digest.
    pub const fn new(digest: ContentDigest) -> Self {
        Self(Some(digest))
    }

    const fn digest(self) -> Option<ContentDigest> {
        self.0
    }
}

/// Resource limits applied to compilation, evaluation, and generated output.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct BuildScriptLimits {
    /// Maximum build-script source bytes accepted before Rhai compilation.
    pub max_script_size: usize,
    /// Maximum Rhai operations in one execution.
    pub max_operations: u64,
    /// Maximum variables alive at once in Rhai.
    pub max_variables: usize,
    /// Maximum scripted function definitions.
    pub max_functions: usize,
    /// Maximum nested scripted function calls.
    pub max_call_depth: usize,
    /// Maximum expression depth at script level.
    pub max_expression_depth: usize,
    /// Maximum expression depth inside scripted functions.
    pub max_function_expression_depth: usize,
    /// Maximum Rhai string length in bytes.
    pub max_string_size: usize,
    /// Maximum Rhai array length.
    pub max_array_size: usize,
    /// Maximum Rhai map size and maximum size of each host-side directive map.
    pub max_map_size: usize,
    /// Maximum bytes in any path supplied by the script.
    pub max_path_bytes: usize,
    /// Maximum segments in any path supplied by the script.
    pub max_path_depth: usize,
    /// Maximum combined bytes in arguments, script diagnostics, metadata, and phase environments.
    pub max_host_directive_bytes: usize,
    /// Maximum number of distinct files generated by one execution.
    pub max_output_files: usize,
    /// Maximum bytes in one generated file.
    pub max_output_file_size: usize,
    /// Maximum combined bytes in all generated files.
    pub max_total_output_size: usize,
    /// Maximum serialized bytes materialized for one persistent build-script state record.
    pub max_cache_state_size: usize,
    /// Maximum value-producing nodes in one declarative task graph.
    pub max_tasks: usize,
    /// Maximum dependency edges, including terminal inputs, in one task graph.
    pub max_task_edges: usize,
    /// Maximum combined bytes in task literals.
    pub max_task_literal_bytes: usize,
    /// Maximum side-effecting terminals in one task graph.
    pub max_task_terminals: usize,
    /// Maximum physical source-tree publication terminals in one task graph.
    pub max_publication_roots: usize,
    /// Ceiling on any single build-task fetch, including a size projected out of fetched JSON.
    pub max_fetch_bytes: u64,
}

impl Default for BuildScriptLimits {
    fn default() -> Self {
        Self {
            max_script_size: 1_048_576,
            max_operations: 1_000_000,
            max_variables: 1_024,
            max_functions: 256,
            max_call_depth: 32,
            max_expression_depth: 64,
            max_function_expression_depth: 32,
            max_string_size: 1_048_576,
            max_array_size: 65_536,
            max_map_size: 4_096,
            max_path_bytes: 4_096,
            max_path_depth: 128,
            max_host_directive_bytes: 1_048_576,
            max_output_files: 256,
            max_output_file_size: 4 * 1_048_576,
            max_total_output_size: 16 * 1_048_576,
            max_cache_state_size: 4 * 1_048_576,
            max_tasks: 4_096,
            max_task_edges: 16_384,
            max_task_literal_bytes: 1_048_576,
            max_task_terminals: 256,
            max_publication_roots: 32,
            // Comfortably above a Minecraft client/server jar, far below "exhaust the machine".
            max_fetch_bytes: 1_024 * 1_048_576,
        }
    }
}

impl BuildScriptLimits {
    fn validate(&self) -> Result<(), BuildScriptError> {
        let limits = [
            (self.max_script_size != 0, "max_script_size"),
            (self.max_operations != 0, "max_operations"),
            (self.max_variables != 0, "max_variables"),
            (self.max_functions != 0, "max_functions"),
            (self.max_call_depth != 0, "max_call_depth"),
            (self.max_expression_depth != 0, "max_expression_depth"),
            (
                self.max_function_expression_depth != 0,
                "max_function_expression_depth",
            ),
            (self.max_string_size != 0, "max_string_size"),
            (self.max_array_size != 0, "max_array_size"),
            (self.max_map_size != 0, "max_map_size"),
            (self.max_path_bytes != 0, "max_path_bytes"),
            (self.max_path_depth != 0, "max_path_depth"),
            (
                self.max_host_directive_bytes != 0,
                "max_host_directive_bytes",
            ),
            (self.max_output_files != 0, "max_output_files"),
            (self.max_output_file_size != 0, "max_output_file_size"),
            (self.max_total_output_size != 0, "max_total_output_size"),
            (self.max_cache_state_size != 0, "max_cache_state_size"),
            (self.max_tasks != 0, "max_tasks"),
            (self.max_task_edges != 0, "max_task_edges"),
            (self.max_task_literal_bytes != 0, "max_task_literal_bytes"),
            (self.max_task_terminals != 0, "max_task_terminals"),
            (self.max_publication_roots != 0, "max_publication_roots"),
            (self.max_fetch_bytes != 0, "max_fetch_bytes"),
        ];
        if let Some((_, name)) = limits.into_iter().find(|(valid, _)| !valid) {
            return Err(BuildScriptError::InvalidLimit(name));
        }

        // The recursion limits also need a ceiling. Rhai walks the AST on the native stack, so a
        // large `max_expression_depth` lets a deeply-parenthesised script overflow it — and a
        // stack overflow aborts the process, which no caller can catch. These fields are public,
        // so an over-generous value is a configuration mistake rather than a script's doing, but
        // the outcome is the same: pin them where the parser stays inside its stack.
        let depths = [
            (
                self.max_call_depth <= Self::MAX_CALL_DEPTH,
                "max_call_depth",
            ),
            (
                self.max_expression_depth <= Self::MAX_EXPRESSION_DEPTH,
                "max_expression_depth",
            ),
            (
                self.max_function_expression_depth <= Self::MAX_EXPRESSION_DEPTH,
                "max_function_expression_depth",
            ),
        ];
        if let Some((_, name)) = depths.into_iter().find(|(valid, _)| !valid) {
            return Err(BuildScriptError::InvalidLimit(name));
        }
        Ok(())
    }

    /// Ceiling on nested calls. Well above anything a build script needs, well below the depth at
    /// which Rhai's evaluator runs out of native stack.
    const MAX_CALL_DEPTH: usize = 256;
    /// Ceiling on expression nesting, bounding the parser's recursion for the same reason.
    const MAX_EXPRESSION_DEPTH: usize = 256;

    const fn task_plan_limits(&self) -> TaskPlanLimits {
        TaskPlanLimits {
            max_tasks: self.max_tasks,
            max_edges: self.max_task_edges,
            max_literal_bytes: self.max_task_literal_bytes,
            max_terminals: self.max_task_terminals,
            max_publication_roots: self.max_publication_roots,
            max_fetch_bytes: self.max_fetch_bytes,
            max_path_bytes: self.max_path_bytes,
            max_path_depth: self.max_path_depth,
        }
    }
}

/// Explicit environment visible to `build.env`.
///
/// Nothing is inherited from the host process. The ordered map makes the input suitable for a
/// future deterministic fingerprint without changing this API.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct BuildScriptEnvironment {
    values: BTreeMap<String, String>,
    /// Resolved Cargo-style build features (`[build.features]`), queried by `build.feature("…")`.
    /// Set by the host from the command-line selection; never inherited from the host process — they
    /// are not secrets and are authoritative, so they bypass the [`Self::HOST_PREFIX`] opt-in that
    /// guards `values`. Always folded into the build-script fingerprint so a changed selection
    /// rebuilds even though the script never declared it as an input.
    features: BTreeSet<String>,
}

impl BuildScriptEnvironment {
    /// The one prefix a host process may forward into a build script.
    ///
    /// A host environment carries credentials (`GITHUB_TOKEN`, `AWS_SECRET_ACCESS_KEY`, npm and
    /// cargo registry tokens, …), and a script that reads a value can forward it straight into a
    /// task fetch URL. Inheriting the whole environment would therefore hand every host secret to
    /// an untrusted `build.rhai` — including a dependency's, which the user never reviewed.
    /// Passing host state stays possible, but only through names the user opted in by choosing
    /// this prefix.
    pub const HOST_PREFIX: &'static str = "JALS_";

    /// Construct an empty environment.
    pub const fn new() -> Self {
        Self {
            values: BTreeMap::new(),
            features: BTreeSet::new(),
        }
    }

    /// Build an environment from a host process's variables, keeping only the opt-in
    /// [`Self::HOST_PREFIX`] names.
    ///
    /// This is the only supported way to cross the host boundary; see [`Self::HOST_PREFIX`] for
    /// why the rest of the environment stays out.
    pub fn from_host<I, K, V>(variables: I) -> Self
    where
        I: IntoIterator<Item = (K, V)>,
        K: Into<String>,
        V: Into<String>,
    {
        variables
            .into_iter()
            .map(|(name, value)| (name.into(), value.into()))
            .filter(|(name, _)| name.starts_with(Self::HOST_PREFIX))
            .collect()
    }

    /// Derive the environment for one project, replacing host-specific project metadata.
    #[must_use]
    pub fn for_project(&self, manifest: &Manifest) -> Self {
        const RESERVED: [&str; 4] = [
            "OUT_DIR",
            "JALS_MANIFEST_DIR",
            "JALS_PACKAGE_NAME",
            "JALS_PACKAGE_VERSION",
        ];

        let mut environment = Self {
            values: self
                .iter()
                .filter(|(name, _)| !RESERVED.contains(name))
                .map(|(name, value)| (name.to_owned(), value.to_owned()))
                .collect(),
            // Not host state to be re-derived: the resolved selection crosses the project boundary
            // unchanged. Named here rather than patched in afterwards so dropping it cannot compile.
            features: self.features.clone(),
        };
        environment.insert("OUT_DIR", RHAI_OUTPUT_ROOT);
        environment.insert("JALS_MANIFEST_DIR", ".");
        if let Some(name) = &manifest.package.name {
            environment.insert("JALS_PACKAGE_NAME", name);
        }
        if let Some(version) = &manifest.package.version {
            environment.insert("JALS_PACKAGE_VERSION", version);
        }
        environment
    }

    /// Insert an explicit variable, returning its previous value.
    pub fn insert(&mut self, name: impl Into<String>, value: impl Into<String>) -> Option<String> {
        self.values.insert(name.into(), value.into())
    }

    /// Get an explicit variable.
    pub fn get(&self, name: &str) -> Option<&str> {
        self.values.get(name).map(String::as_str)
    }

    /// Iterate variables in lexical order.
    pub fn iter(&self) -> impl ExactSizeIterator<Item = (&str, &str)> {
        self.values
            .iter()
            .map(|(name, value)| (name.as_str(), value.as_str()))
    }

    /// Number of explicit variables.
    pub fn len(&self) -> usize {
        self.values.len()
    }

    /// Whether the environment is empty.
    pub fn is_empty(&self) -> bool {
        self.values.is_empty()
    }

    /// This environment with its resolved build features set to `features`.
    #[must_use]
    pub fn with_features(mut self, features: BTreeSet<String>) -> Self {
        self.features = features;
        self
    }

    /// Whether build feature `name` is enabled (backs `build.feature("…")`).
    pub fn has_feature(&self, name: &str) -> bool {
        self.features.contains(name)
    }

    /// Iterate the enabled build features in lexical order (backs `build.features()`).
    pub fn features(&self) -> impl ExactSizeIterator<Item = &str> {
        self.features.iter().map(String::as_str)
    }
}

impl FromIterator<(String, String)> for BuildScriptEnvironment {
    fn from_iter<T: IntoIterator<Item = (String, String)>>(iter: T) -> Self {
        Self {
            values: iter.into_iter().collect(),
            features: BTreeSet::new(),
        }
    }
}

/// One script-reported diagnostic.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum BuildScriptDiagnostic {
    /// A non-fatal warning.
    Warning(String),
    /// A fatal diagnostic. Any such diagnostic prevents publication.
    Error(String),
}

impl BuildScriptDiagnostic {
    /// Diagnostic message without its severity.
    pub fn message(&self) -> &str {
        match self {
            Self::Warning(message) | Self::Error(message) => message,
        }
    }

    /// Whether this diagnostic prevents publication.
    pub const fn is_error(&self) -> bool {
        matches!(self, Self::Error(_))
    }
}

/// Deterministic result of one successfully published build-script execution.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct BuildScriptOutput {
    /// Storage revision containing the published files. It is unchanged for an exact no-op.
    pub revision: Revision,
    /// Every file written below [`RHAI_OUTPUT_ROOT`], in key order.
    pub generated_files: BTreeSet<FileKey>,
    /// Generated or project source files added by the script, in key order.
    pub generated_sources: BTreeSet<FileKey>,
    /// Additional project classpath entries, in key order.
    pub additional_classpath: BTreeSet<FileKey>,
    /// Extra `javac` arguments in script call order.
    pub javac_args: Vec<String>,
    /// Extra JVM arguments in script call order.
    pub jvm_args: Vec<String>,
    /// Explicit environment for compilation.
    pub compile_env: BTreeMap<String, String>,
    /// Explicit environment for execution.
    pub run_env: BTreeMap<String, String>,
    /// Project files that invalidate this result, in key order.
    pub rerun_files: BTreeSet<FileKey>,
    /// Environment names that invalidate this result, in lexical order.
    pub rerun_env: BTreeSet<String>,
    /// Script warnings and any non-fatal cache-persistence warning. Successful results never
    /// contain an error diagnostic.
    pub diagnostics: Vec<BuildScriptDiagnostic>,
    /// Script metadata, in lexical key order.
    pub metadata: BTreeMap<String, String>,
    /// Declarative host tasks recorded by the script.
    pub task_plan: TaskPlan,
}

/// Canonical output-root-relative path returned by `output.write` and `output.write_text`.
///
/// Scripts pass this value directly to `build.add_source` or `build.add_classpath`. Hosts can use
/// [`key`](Self::key) to access the fully rooted storage identity.
#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct BuildScriptOutputPath {
    key: FileKey,
}

impl BuildScriptOutputPath {
    /// Fully rooted key below [`RHAI_OUTPUT_ROOT`].
    pub const fn key(&self) -> &FileKey {
        &self.key
    }
}

/// Aggregate-local knowledge used to reconcile stale generated files safely.
///
/// Durable ownership is recovered from the project artifact cache when possible. A stale file is
/// removed only when its current bytes still match verified bytes known to this session; unknown
/// or externally modified files are never deleted. If durable cache publication fails, this
/// in-memory ownership remains valid for the current session but cannot protect cleanup after a
/// process restart.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct BuildScriptSession {
    outputs: BTreeMap<FileKey, Vec<u8>>,
}

impl BuildScriptSession {
    /// Construct an empty session.
    pub const fn new() -> Self {
        Self {
            outputs: BTreeMap::new(),
        }
    }

    /// Keys known to have been published through this session, in key order.
    pub fn known_outputs(&self) -> impl ExactSizeIterator<Item = &FileKey> {
        self.outputs.keys()
    }
}

