struct CacheIdentity;

impl CacheIdentity {
    fn state(scope: BuildScriptCacheScope, script: &FileKey) -> ContentDigest {
        Self::digest(b"jals-build:build-script-state", scope, script, None)
    }

    fn output(scope: BuildScriptCacheScope, script: &FileKey, output: &FileKey) -> ContentDigest {
        Self::digest(
            b"jals-build:build-script-output",
            scope,
            script,
            Some(output),
        )
    }

    fn digest(
        domain: &[u8],
        scope: BuildScriptCacheScope,
        script: &FileKey,
        output: Option<&FileKey>,
    ) -> ContentDigest {
        let script = ContentDigest::of(script.to_string().as_bytes());
        let output = output.map(|key| ContentDigest::of(key.to_string().as_bytes()));
        let mut bytes =
            Vec::with_capacity(domain.len() + 4 + 1 + 32 + 32 + usize::from(output.is_some()) * 32);
        bytes.extend_from_slice(domain);
        bytes.extend_from_slice(&BUILD_SCRIPT_API_VERSION.to_be_bytes());
        match scope.digest() {
            None => bytes.push(0),
            Some(digest) => {
                bytes.push(1);
                bytes.extend_from_slice(digest.as_bytes());
            }
        }
        bytes.extend_from_slice(script.as_bytes());
        if let Some(output) = output {
            bytes.extend_from_slice(output.as_bytes());
        }
        ContentDigest::of(&bytes)
    }
}

/// One source location reported by the Rhai parser or evaluator.
///
/// Lines and columns are both 1-based. Rhai's internal beginning-of-line marker has column zero;
/// it is normalized to column one when exposed through this type.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct BuildScriptPosition {
    line: u32,
    column: u32,
}

impl BuildScriptPosition {
    /// 1-based source line.
    pub const fn line(self) -> u32 {
        self.line
    }

    /// 1-based character column.
    pub const fn column(self) -> u32 {
        self.column
    }
}

/// Failure to configure, evaluate, or atomically publish a build script.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum BuildScriptError {
    /// A zero limit would disable a Rhai bound and is therefore rejected.
    InvalidLimit(&'static str),
    /// The configured script path is not a portable file key.
    InvalidScriptPath { path: String, reason: String },
    /// The configured script exceeds the source byte limit and was not passed to Rhai.
    ScriptTooLarge {
        script: FileKey,
        size: usize,
        limit: usize,
    },
    /// An environment input exceeds the configured Rhai data bounds.
    EnvironmentLimit(String),
    /// Reading the script or publishing its outputs failed in project storage.
    Storage {
        operation: &'static str,
        error: jals_storage::Error,
    },
    /// Rhai compilation failed.
    Compile {
        script: FileKey,
        position: Option<BuildScriptPosition>,
        message: String,
    },
    /// Rhai evaluation or a registered host operation failed.
    Execute {
        script: FileKey,
        position: Option<BuildScriptPosition>,
        message: String,
    },
    /// The script called `build.error`; no generated files were published.
    ReportedErrors(Vec<BuildScriptDiagnostic>),
}

impl BuildScriptError {
    /// Configured script path for Rhai compilation and evaluation failures.
    pub const fn script_path(&self) -> Option<&FileKey> {
        match self {
            Self::ScriptTooLarge { script, .. }
            | Self::Compile { script, .. }
            | Self::Execute { script, .. } => Some(script),
            _ => None,
        }
    }

    /// Structured Rhai source position for compilation and evaluation failures, when available.
    pub const fn position(&self) -> Option<BuildScriptPosition> {
        match self {
            Self::Compile { position, .. } | Self::Execute { position, .. } => *position,
            _ => None,
        }
    }
}

impl fmt::Display for BuildScriptError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::InvalidLimit(name) => write!(f, "build-script limit `{name}` must be non-zero"),
            Self::InvalidScriptPath { path, reason } => {
                write!(f, "invalid build-script file `{path}`: {reason}")
            }
            Self::ScriptTooLarge {
                script,
                size,
                limit,
            } => write!(
                f,
                "build script `{script}` has {size} bytes, exceeding the source limit of {limit}"
            ),
            Self::EnvironmentLimit(message) => f.write_str(message),
            Self::Storage { operation, error } => {
                write!(f, "build script could not {operation}: {error}")
            }
            Self::Compile {
                script, message, ..
            } => {
                write!(f, "could not compile build script `{script}`: {message}")
            }
            Self::Execute {
                script, message, ..
            } => {
                write!(f, "build script `{script}` failed: {message}")
            }
            Self::ReportedErrors(diagnostics) => write!(
                f,
                "build script reported {} error diagnostic(s)",
                diagnostics.iter().filter(|item| item.is_error()).count()
            ),
        }
    }
}

impl CoreError for BuildScriptError {}

