    /// A script can forward anything `build.env` returns into a task fetch URL, so the host
    /// environment must not cross the boundary wholesale — otherwise every credential on the
    /// machine is readable by an unreviewed `build.rhai`, including a dependency's.
    #[test]
    fn from_host_keeps_only_the_opt_in_prefix() {
        let environment = BuildScriptEnvironment::from_host([
            ("GITHUB_TOKEN", "ghp_secret"),
            ("AWS_SECRET_ACCESS_KEY", "aws_secret"),
            ("PATH", "/usr/bin"),
            ("HOME", "/home/user"),
            ("MC_SIDE", "server"),
            ("JALS_MC_SIDE", "client"),
        ]);

        assert_eq!(
            environment.iter().collect::<Vec<_>>(),
            vec![("JALS_MC_SIDE", "client")]
        );
        for secret in ["GITHUB_TOKEN", "AWS_SECRET_ACCESS_KEY", "PATH", "HOME"] {
            assert_eq!(
                environment.get(secret),
                None,
                "{secret} must not be visible"
            );
        }
    }

    #[test]
    fn collects_directives_environment_diagnostics_and_metadata() {
        block_on_inline(async {
            let script = r#"
                if build.env("PROFILE") != "debug" || build.env("MISSING") != () {
                    throw "bad environment";
                }
                build.rerun_if_changed("inputs/schema.txt");
                build.rerun_if_env_changed("PROFILE");
                build.add_source("src/Main.java");
                build.add_classpath("lib/api.jar");
                build.add_javac_arg("-Xlint:all");
                build.add_jvm_arg("-ea");
                build.set_compile_env("LANG", "C");
                build.set_run_env("MODE", "test");
                build.warning("generated fallback");
                build.metadata("schema", "v1");
            "#;
            let mut storage = storage(
                script,
                [
                    file("inputs/schema.txt", "schema"),
                    file("src/Main.java", "class Main {}"),
                    file("lib/api.jar", "jar"),
                ],
            );
            let mut environment = BuildScriptEnvironment::new();
            environment.insert("PROFILE", "debug");
            let output = run(
                &mut storage,
                &environment,
                &BuildScriptLimits::default(),
                &mut BuildScriptSession::new(),
            )
            .await
            .unwrap();

            assert_eq!(
                output.rerun_files,
                BTreeSet::from([FileKey::parse("inputs/schema.txt").unwrap()])
            );
            assert_eq!(output.rerun_env, BTreeSet::from(["PROFILE".into()]));
            assert_eq!(
                output.generated_sources,
                BTreeSet::from([FileKey::parse("src/Main.java").unwrap()])
            );
            assert_eq!(
                output.additional_classpath,
                BTreeSet::from([FileKey::parse("lib/api.jar").unwrap()])
            );
            assert_eq!(output.javac_args, ["-Xlint:all"]);
            assert_eq!(output.jvm_args, ["-ea"]);
            assert_eq!(output.compile_env.get("LANG").unwrap(), "C");
            assert_eq!(output.run_env.get("MODE").unwrap(), "test");
            assert_eq!(
                output.diagnostics,
                [BuildScriptDiagnostic::Warning("generated fallback".into())]
            );
            assert_eq!(output.metadata.get("schema").unwrap(), "v1");
        });
    }

